head.b:skin:
/*==========================================================
                HADOTI NEWS PRO v2.0 (CLEANED)
==========================================================*/
:root {
  --primary: #0d6efd;
  --primary-dark: #0b5ed7;
  --secondary: #ff6b00;
  --success: #198754;
  --danger: #dc3545;
  --warning: #ffc107;
  --info: #0dcaf0;
  --body-bg: #f5f7fb;
  --card-bg: #ffffff;
  --text: #222222;
  --text-light: #666666;
  --heading: #111111;
  --border: #e5e7eb;
  --radius: 10px;
  --shadow: 0 8px 25px rgba(0,0,0,.08);
  --container: 1280px;
  --transition: .30s ease;
  --font: Arial, Helvetica, sans-serif;
}

/* CSS Reset & Basics */
*, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }
html { scroll-behavior: smooth; }
body { background: var(--body-bg); font-family: var(--font); font-size: 16px; line-height: 1.7; color: var(--text); overflow-x: hidden; -webkit-font-smoothing: antialiased; }
body.dark-mode { background: #121212; color: #eee; }
body.dark-mode #site-header, body.dark-mode .header-main, body.dark-mode .main-nav, body.dark-mode .card, body.dark-mode .breaking-news-wrap, body.dark-mode .sidebar .widget { background: #1e1e1e; border-color: #333; }
body.dark-mode h1, body.dark-mode h2, body.dark-mode h3, body.dark-mode h4, body.dark-mode h5, body.dark-mode h6, body.dark-mode a { color: #fff; }
body.dark-mode p { color: #aaa; }

img { display: block; max-width: 100%; height: auto; }
a { text-decoration: none; color: inherit; transition: var(--transition); }
a:hover { color: var(--primary); }
ul, ol { list-style: none; }

/* Layout Grid */
.container { width: 100%; max-width: var(--container); margin: auto; padding: 0 18px; }
.row { display: flex; flex-wrap: wrap; margin: 0 -15px; }
.col-8 { width: 66.6666%; padding: 15px; }
.col-4 { width: 33.3333%; padding: 15px; }
@media(max-width: 992px) { .col-8, .col-4 { width: 100%; } }

/* Header & Nav */
#site-header { background: #fff; position: sticky; top: 0; z-index: 9999; box-shadow: 0 2px 12px rgba(0,0,0,.08); }
.topbar { background: var(--primary); color: #fff; font-size: 14px; padding: 8px 0; }
.d-flex { display: flex; }
.justify-between { justify-content: space-between; }
.align-center { align-items: center; }
.live-dot { width: 100%; max-width: 10px; height: 10px; background: #ff0000; border-radius: 50%; display: inline-block; animation: liveBlink 1s infinite; margin-right: 5px; }
@keyframes liveBlink { 0%, 100% { opacity: 1; } 50% { opacity: .3; } }
.header-main { background: #fff; padding: 18px 0; border-bottom: 1px solid var(--border); }
.logo-title { font-size: 32px; font-weight: 800; color: var(--primary); margin: 0; }
.logo-tagline { font-size: 14px; color: var(--text-light); }
.header-actions { display: flex; gap: 12px; }
.header-actions button { width: 44px; height: 44px; border-radius: 50%; background: #f5f5f5; cursor: pointer; transition: var(--transition); font-size: 18px; display: inline-flex; align-items: center; justify-content: center; }
.header-actions button:hover { background: var(--primary); color: #fff; }
.main-nav { background: #ffffff; border-bottom: 1px solid var(--border); }
.nav-menu { display: flex; gap: 24px; }
.nav-menu a { display: block; padding: 16px 0; font-size: 15px; font-weight: 600; }
.nav-menu .active-menu { display: flex; }

@media(max-width: 992px) {
  .nav-menu { display: none; flex-direction: column; width: 100%; padding-bottom: 15px; }
  .nav-menu.active { display: flex; }
}

/* Breaking News */
#breaking-news { margin: 20px 0; }
.breaking-news-wrap { display: flex; align-items: center; background: #fff; border-radius: var(--radius); overflow: hidden; box-shadow: var(--shadow); }
.breaking-title { padding: 12px 20px; background: var(--primary); color: #fff; font-weight: 700; white-space: nowrap; }
.breaking-content { flex: 1; padding: 0 15px; }

/* Main Section */
#main-wrapper { padding: 30px 0; }
.sidebar .widget { background: #fff; margin-bottom: 25px; padding: 20px; border-radius: var(--radius); box-shadow: var(--shadow); }
.widget h2 { font-size: 18px; font-weight: 700; margin-bottom: 15px; padding-bottom: 10px; border-bottom: 2px solid var(--primary); }

/* Footer */
#footer-wrapper { background: #111827; color: #ffffff; padding: 60px 0 20px; margin-top: 60px; }
.footer-top { display: grid; grid-template-columns: repeat(3, 1fr); gap: 40px; }
@media(max-width: 768px) { .footer-top { grid-template-columns: 1fr; } }
.footer-column h3 { margin-bottom: 20px; font-size: 22px; color: #fff; }
.footer-column p, .footer-column li { color: #cbd5e1; margin-bottom: 10px; }
.footer-bottom { margin-top: 40px; padding-top: 20px; border-top: 1px solid rgba(255,255,255,.1); text-align: center; font-size: 15px; }

/* Back to top */
#backTop { position: fixed; bottom: 30px; right: 30px; width: 50px; height: 50px; background: var(--primary); color: #fff; border: none; border-radius: 50%; display: none; cursor: pointer; font-size: 20px; box-shadow: var(--shadow); z-index: 999; }

body.script:
document.addEventListener("DOMContentLoaded", function() {
    // 1. Live Date Implementation
    const dateEl = document.getElementById("current-date");
    if(dateEl) {
        const options = { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' };
        dateEl.innerHTML = new Date().toLocaleDateString('en-IN', options);
    }

    // 2. Footer Year
    const yearEl = document.getElementById("current-year");
    if(yearEl) { yearEl.textContent = new Date().getFullYear(); }

    // 3. Dark Mode Toggle
    const darkBtn = document.getElementById("darkModeBtn");
    if (darkBtn) {
        darkBtn.onclick = function() {
            document.body.classList.toggle("dark-mode");
            localStorage.setItem("theme", document.body.classList.contains("dark-mode") ? "dark" : "light");
        };
        if (localStorage.getItem("theme") === "dark") {
            document.body.classList.add("dark-mode");
        }
    }

    // 4. Mobile Menu Toggle
    const menuBtn = document.getElementById("mobileMenuBtn");
    const navMenu = document.getElementById("navMenu");
    if (menuBtn && navMenu) {
        menuBtn.onclick = function() {
            navMenu.classList.toggle("active");
        };
    }

    // 5. Back To Top
    const backTopBtn = document.getElementById("backTop");
    window.addEventListener("scroll", function() {
        if (window.pageYOffset > 300) {
            backTopBtn.style.display = "block";
        } else {
            backTopBtn.style.display = "none";
        }
    });
    backTopBtn.onclick = function() {
        window.scrollTo({ top: 0, behavior: "smooth" });
    };

    // 6. Search Placeholder Alert
    const searchBtn = document.getElementById("searchBtn");
    if(searchBtn) {
        searchBtn.onclick = function() {
            alert("Search functionality is active via Blogger Default Search Widget!");
        };
    }
});
